using System;
using System.IO;

namespace YS.Knife
{
    public class StreamBody : IDisposable
    {
        public Stream Stream { get; set; }
        public string ContentType { get; set; }
        public string FileName { get; set; }
        public long Length { get; set; }

        public static StreamBody FromStream(Stream stream, string contentType, string fileName, long length, bool autoSeekBegin = true)
        {
            return new StreamBody { Stream = stream, ContentType = contentType, FileName = fileName, Length = length };
        }

        public void Dispose() { }
    }
}

public interface IDownloadService
{
    YS.Knife.StreamBody GetFile(int id);
}

[YS.Knife.ExposeApi(typeof(IDownloadService))]
public class TestController
{
}

