using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
namespace 
{
    [ApiController]
    [Route("api/[controller]")]
    public class DownloadController : ControllerBase
    {
        private readonly global::IDownloadService iDownloadService;
        public DownloadController(global::IDownloadService iDownloadService)
        {
            this.iDownloadService = iDownloadService;
        }

        [Route("GetFile/{id}")]
        [HttpGet]
        public global::Microsoft.AspNetCore.Mvc.IActionResult GetFile([FromRoute] int id)
        {
            var __sb_result = this.iDownloadService.GetFile(id);
            this.HttpContext.Response.RegisterForDispose(__sb_result);
            return this.File(__sb_result.Stream, __sb_result.ContentType, __sb_result.FileName);
        }
    }
}
